#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int a,b,c,d; scanf("%d %d %d %d", &a, &b, &c, &d);
        if(a + c == 180 && b + d == 180) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

